-- ============================================================
-- KPI VIEWS — Wingman Results Page
-- ============================================================

-- 1. KPI Global: score moyen pondéré, pass rate, J-exam projection
CREATE OR REPLACE VIEW v_kpi_global AS
SELECT
    pr.user_id,
    ROUND(AVG(pr.score_pct), 1)                                        AS score_global,
    COUNT(*) FILTER (WHERE pr.score_pct >= 70)::FLOAT / NULLIF(COUNT(*),0) * 100
                                                                       AS pass_rate_pct,
    ROUND(
        SUM(pr.score_pct * pr.questions_attempted) /
        NULLIF(SUM(pr.questions_attempted), 0), 1
    )                                                                  AS weighted_score,
    SUM(pr.questions_attempted)                                        AS total_questions,
    COUNT(DISTINCT pr.lm_id)                                           AS lms_attempted,
    COUNT(*) FILTER (WHERE pr.status = 'mastered')                     AS los_mastered,
    COUNT(*) FILTER (WHERE pr.status = 'weak')                         AS los_weak,
    COUNT(*) FILTER (WHERE pr.status = 'in_progress')                  AS los_in_progress,
    MAX(pr.last_attempt_date)                                          AS last_activity
FROM performance_records pr
WHERE pr.user_id IS NOT NULL
GROUP BY pr.user_id;

-- 2. Score par topic
CREATE OR REPLACE VIEW v_kpi_by_topic AS
SELECT
    pr.user_id,
    lm.topic_code                                                      AS topic,
    ROUND(AVG(pr.score_pct), 1)                                        AS avg_score,
    SUM(pr.questions_attempted)                                        AS total_questions,
    SUM(pr.questions_correct)                                          AS total_correct,
    COUNT(DISTINCT pr.lm_id)                                           AS lms_attempted,
    COUNT(*) FILTER (WHERE pr.status = 'mastered')                     AS los_mastered,
    COUNT(*) FILTER (WHERE pr.status = 'weak')                         AS los_weak,
    MAX(pr.last_attempt_date)                                          AS last_seen
FROM performance_records pr
JOIN learning_modules lm ON lm.id = pr.lm_id
GROUP BY pr.user_id, lm.topic_code;

-- 3. Score par LM
CREATE OR REPLACE VIEW v_kpi_by_lm AS
SELECT
    mm.user_id,
    lm.topic_code,
    lm.code                                                            AS lm_code,
    lm.title                                                           AS lm_title,
    mm.score_pct,
    mm.questions_attempted,
    mm.los_completed,
    mm.los_total,
    ROUND(mm.los_completed::NUMERIC / NULLIF(mm.los_total,0) * 100, 0) AS los_completion_pct,
    mm.mastery_level,
    mm.last_updated
FROM lm_mastery mm
JOIN learning_modules lm ON lm.id = mm.lm_id;

-- 4. Score par LOS (table résultats granulaire)
CREATE OR REPLACE VIEW v_kpi_by_los AS
SELECT
    pr.user_id,
    lm.topic_code,
    lm.code                                                            AS lm_code,
    lm.title                                                           AS lm_title,
    lo.code                                                            AS los_id,
    lo.description                                                     AS los_desc,
    pr.questions_attempted,
    pr.questions_correct,
    pr.score_pct,
    pr.last_attempt_date,
    CURRENT_DATE - pr.last_attempt_date                                AS days_since,
    pr.trend,
    pr.status
FROM performance_records pr
JOIN learning_modules lm ON lm.id = pr.lm_id
JOIN learning_outcomes lo ON lo.id = pr.los_id;

-- 5. KPI Progression hebdomadaire
CREATE OR REPLACE VIEW v_kpi_weekly_progress AS
SELECT
    user_id,
    snapshot_date,
    curriculum_progress_pct,
    avg_score_pct,
    total_questions_done,
    streak_days,
    avg_score_pct - LAG(avg_score_pct) OVER (PARTITION BY user_id ORDER BY snapshot_date)
                                                                       AS score_delta,
    total_questions_done - LAG(total_questions_done) OVER (PARTITION BY user_id ORDER BY snapshot_date)
                                                                       AS questions_delta
FROM progress_snapshots
ORDER BY user_id, snapshot_date;

-- 6. KPI Tempo: étude par jour (heatmap)
CREATE OR REPLACE VIEW v_kpi_daily_activity AS
SELECT
    s.user_id,
    DATE(s.started_at)                                                 AS study_date,
    COUNT(DISTINCT s.id)                                               AS sessions,
    SUM(s.duration_minutes)                                            AS total_minutes,
    COUNT(qa.id)                                                       AS questions_done,
    ROUND(AVG(qa.is_correct::INT) * 100, 1)                           AS daily_accuracy
FROM sessions s
LEFT JOIN question_attempts qa ON qa.session_id = s.id
GROUP BY s.user_id, DATE(s.started_at);

-- 7. KPI Alertes actives par sévérité
CREATE OR REPLACE VIEW v_kpi_alerts AS
SELECT
    a.user_id,
    a.alert_type,
    lm.topic_code,
    lm.code    AS lm_code,
    lm.title   AS lm_title,
    lo.code    AS los_code,
    a.message,
    a.created_at
FROM alerts a
JOIN learning_modules lm ON lm.id = a.lm_id
LEFT JOIN learning_outcomes lo ON lo.id = a.los_id
WHERE a.is_active = TRUE
ORDER BY
    CASE a.alert_type WHEN 'critical' THEN 1 WHEN 'warning' THEN 2 ELSE 3 END,
    a.created_at DESC;

-- 8. KPI J-Exam score projection (linear regression approximation)
CREATE OR REPLACE VIEW v_kpi_projection AS
WITH weekly AS (
    SELECT user_id, snapshot_date, avg_score_pct,
           ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY snapshot_date) AS wk
    FROM progress_snapshots
),
regression AS (
    SELECT user_id,
           REGR_SLOPE(avg_score_pct, wk)     AS slope,
           REGR_INTERCEPT(avg_score_pct, wk) AS intercept,
           MAX(wk)                            AS last_wk,
           MAX(avg_score_pct)                AS current_score
    FROM weekly
    GROUP BY user_id
)
SELECT
    r.user_id,
    ROUND(r.current_score::NUMERIC, 1)                                 AS current_score,
    ROUND((r.intercept + r.slope * (r.last_wk + 19))::NUMERIC, 1)     AS projected_score_at_exam,
    ROUND(r.slope::NUMERIC, 2)                                         AS weekly_improvement,
    CASE
        WHEN (r.intercept + r.slope * (r.last_wk + 19)) >= 70 THEN 'on_track'
        WHEN (r.intercept + r.slope * (r.last_wk + 19)) >= 60 THEN 'at_risk'
        ELSE 'critical'
    END                                                                AS forecast_status
FROM regression r;
